"use strict";(self.webpackChunkfedpat_docs=self.webpackChunkfedpat_docs||[]).push([[7569],{6814:(e,n,a)=>{a.r(n),a.d(n,{assets:()=>l,contentTitle:()=>o,default:()=>u,frontMatter:()=>i,metadata:()=>s,toc:()=>c});var r=a(4848),t=a(8453);const i={id:"java-skill-raw",title:"SKILL.md \u2014 Java",sidebar_label:"SKILL.md"},o="SKILL.md \u2014 Java",s={id:"ia/claude-skills/java-skill-raw",title:"SKILL.md \u2014 Java",description:"Archivo de instrucciones que Claude usa internamente. Si encontr\xe1s algo para mejorar, abr\xed un PR directamente.",source:"@site/docs/ia/claude-skills/java-skill-raw.md",sourceDirName:"ia/claude-skills",slug:"/ia/claude-skills/java-skill-raw",permalink:"/flock-tech-guides/ia/claude-skills/java-skill-raw",draft:!1,unlisted:!1,editUrl:"https://github.com/Mujics/flock-tech-guides/tree/main/flock-tech-guides/docs/ia/claude-skills/java-skill-raw.md",tags:[],version:"current",frontMatter:{id:"java-skill-raw",title:"SKILL.md \u2014 Java",sidebar_label:"SKILL.md"},sidebar:"docs",previous:{title:"Java Skill",permalink:"/flock-tech-guides/ia/claude-skills/java-skill"},next:{title:"NetCore Skill",permalink:"/flock-tech-guides/ia/claude-skills/netcore-skill"}},l={},c=[];function d(e){const n={a:"a",admonition:"admonition",code:"code",h1:"h1",hr:"hr",p:"p",pre:"pre",...(0,t.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(n.h1,{id:"skillmd--java",children:"SKILL.md \u2014 Java"}),"\n",(0,r.jsx)(n.p,{children:"Archivo de instrucciones que Claude usa internamente. Si encontr\xe1s algo para mejorar, abr\xed un PR directamente."}),"\n",(0,r.jsx)(n.admonition,{title:"Contribuir",type:"info",children:(0,r.jsxs)(n.p,{children:[(0,r.jsx)(n.a,{href:"https://github.com/Flock-engineering/flock-tech-guides/edit/dev/static/skills/java/SKILL.md",children:"\u270f\ufe0f Sugerir correcci\xf3n en GitHub"})," \u2014 GitHub te propone hacer fork y PR autom\xe1ticamente si no ten\xe9s permisos de push."]})}),"\n",(0,r.jsx)(n.p,{children:(0,r.jsx)(n.a,{href:"pathname:///flock-tech-guides/skills/java/SKILL.md",children:"\u2b07 Descargar SKILL.md"})}),"\n",(0,r.jsx)(n.hr,{}),"\n",(0,r.jsx)(n.pre,{children:(0,r.jsx)(n.code,{className:"language-md",children:'---\nname: java\ndescription: >\n  Java moderno con calidad de c\xf3digo, Lombok est\xe1ndar y seguridad de tipos.\n  Trigger: crear clase Java, refactorizar Java, escribir servicio Java, mejorar calidad Java\nlicense: MIT\nmetadata:\n  author: tu-proyecto\n  version: \'1.1\'\n  scope: [root]\n  auto_invoke:\n    - \'Crear clase Java\'\n    - \'Crear servicio Java\'\n    - \'Refactorizar Java\'\n    - \'Mejorar calidad Java\'\n    - \'Escribir c\xf3digo Java\'\n    - \'Usar Lombok\'\nallowed-tools: Read, Edit, Write, Glob, Grep, Bash\n---\n\n# Java Skill\n\n## Critical Rules\n\n### ALWAYS\n\n- Usar Lombok como librer\xeda est\xe1ndar para eliminar boilerplate\n- Usar `@RequiredArgsConstructor` para inyecci\xf3n por constructor \u2014 nunca `@Autowired` en campo\n- Usar `@Slf4j` para logging \u2014 nunca crear `Logger` manualmente\n- Usar `@Builder` para construcci\xf3n de objetos con m\xe1s de 3 par\xe1metros\n- Usar `Optional<T>` como retorno en lugar de `null`\n- Aplicar Single Responsibility: clases < 200 l\xedneas, m\xe9todos < 20 l\xedneas\n- Declarar campos inmutables con `final`\n- Usar `record` para objetos de datos inmutables (Java 16+)\n- Usar generics con tipo expl\xedcito \u2014 nunca raw types (`List` \u2192 `List<String>`)\n- Extraer constantes: no magic numbers ni magic strings en la l\xf3gica\n- Usar guard clauses para validar inputs al inicio del m\xe9todo\n- Preferir composici\xf3n sobre herencia\n- Usar streams para procesar colecciones en vez de loops imperativos\n- Usar pattern matching con `instanceof` (Java 16+) en vez de casteos expl\xedcitos\n- Lanzar excepciones espec\xedficas y documentadas, nunca `Exception` o `Throwable` gen\xe9ricos\n- Usar `@NonNull` (Lombok) o `Objects.requireNonNull` para precondiciones de par\xe1metros\n\n### NEVER\n\n- Usar `@Data` en entidades JPA \u2014 causa N+1 con lazy loading e infinite recursion en bidireccionales\n- Usar `@Setter` a nivel de clase en entidades \u2014 preferir builder o m\xe9todos de dominio\n- Usar `@ToString` sin `exclude` en entidades con relaciones lazy o bidireccionales\n- Usar `@SneakyThrows` para ocultar excepciones que deber\xedan manejarse\n- Crear `Logger` manualmente (`LoggerFactory.getLogger(...)`) \u2014 usar `@Slf4j`\n- Inyectar dependencias con `@Autowired` en campo \u2014 usar `@RequiredArgsConstructor`\n- Retornar `null` \u2014 usar `Optional<T>` o lanzar excepci\xf3n\n- Usar raw types: `List`, `Map`, `Set` sin par\xe1metro de tipo\n- Capturar excepciones con `catch` vac\xedo o solo con `e.printStackTrace()`\n- Crear clases con m\xe1s de una responsabilidad (God classes)\n- Usar estado mutable est\xe1tico (`static` + no-`final`)\n- Comparar Strings con `==` (usar `.equals()`)\n- Duplicar l\xf3gica entre clases \u2014 extraer a clase base, interfaz o utility\n\n---\n\n## Lombok \u2014 Librer\xeda Est\xe1ndar\n\n### Constructores\n\n```java\n// \u2705 @RequiredArgsConstructor \u2014 genera constructor para campos final y @NonNull\n// Es el est\xe1ndar para inyecci\xf3n de dependencias en Spring Boot\n@Service\n@RequiredArgsConstructor\npublic class UserService {\n    private final UserRepository userRepository;  // inyectado por constructor\n    private final UserMapper     userMapper;       // inyectado por constructor\n}\n\n// \u2705 @NoArgsConstructor \u2014 constructor sin argumentos\n// Requerido por JPA y Jackson para deserializaci\xf3n\n@Entity\n@NoArgsConstructor   // JPA lo necesita\n@AllArgsConstructor  // para tests y factory methods\npublic class User { ... }\n\n// @AllArgsConstructor \u2014 todos los campos (combinar con factory method)\n```\n\n### Logging\n\n```java\n// \u274c MAL \u2014 Logger manual (boilerplate repetido en cada clase)\npublic class UserService {\n    private static final Logger log = LoggerFactory.getLogger(UserService.class);\n}\n\n// \u2705 BIEN \u2014 @Slf4j crea "log" autom\xe1ticamente\n@Slf4j\n@Service\npublic class UserService {\n    public void create(User user) {\n        log.info("Creating user with email={}", user.getEmail());\n        log.debug("Full user data: {}", user);\n        log.error("Failed to create user: {}", e.getMessage(), e);\n    }\n}\n\n// Para Log4j2: usar @Log4j2\n```\n\n### Getters, Setters y Equals\n\n```java\n// En entidades JPA \u2014 control granular (NUNCA @Data)\n@Entity\n@Getter                                   // getters en todos los campos\n@Setter                                   // setters en todos los campos (o a nivel de campo)\n@NoArgsConstructor\n@EqualsAndHashCode(of = "id")             // solo el id define igualdad en entidades\n@ToString(exclude = {"password", "orders"}) // excluir sensibles y colecciones lazy\npublic class User {\n    @Id\n    @GeneratedValue(strategy = GenerationType.IDENTITY)\n    private Long id;\n\n    private String name;\n\n    @Setter(AccessLevel.NONE)  // campo calculado \u2014 no exponer setter\n    private String slug;\n\n    @OneToMany(fetch = FetchType.LAZY)\n    @ToString.Exclude   // alternativa por campo \u2014 evita N+1 en toString\n    private List<Order> orders;\n}\n\n// En DTOs simples (no entidades) \u2014 @Data est\xe1 bien\n@Data\n@NoArgsConstructor\n@AllArgsConstructor\npublic class UserDto {\n    private Long   id;\n    private String name;\n    private String email;\n}\n```\n\n### Builder\n\n```java\n// \u2705 @Builder \u2014 patr\xf3n builder sin escribir el builder manualmente\n@Builder\n@Getter\npublic class EmailMessage {\n    private final String       to;\n    private final String       subject;\n\n    @Builder.Default  // SIN @Builder.Default el campo ser\xeda null en el builder\n    private final String       body = "";\n\n    @Builder.Default\n    private final List<String> cc   = List.of();\n\n    @Builder.Default\n    private final boolean      highPriority = false;\n}\n\n// Uso \u2014 igual que builder manual pero sin el boilerplate\nEmailMessage email = EmailMessage.builder()\n    .to("user@example.com")\n    .subject("Bienvenido")\n    .body("Tu cuenta fue creada.")\n    .cc(List.of("admin@example.com"))\n    .build();\n\n// @Builder(toBuilder = true) \u2014 crea copia con un campo modificado\nEmailMessage reminder = email.toBuilder()\n    .subject("Recordatorio: " + email.getSubject())\n    .build();\n```\n\n### @SuperBuilder \u2014 Builder con Herencia\n\n```java\n// Cuando la clase padre tambi\xe9n usa @Builder, usar @SuperBuilder en ambas\n@SuperBuilder\n@Getter\npublic abstract class BaseEntity {\n    private final Long   id;\n    private final String createdBy;\n}\n\n@SuperBuilder\n@Getter\npublic class Product extends BaseEntity {\n    private final String name;\n    private final double price;\n}\n\n// Uso:\nProduct p = Product.builder()\n    .id(1L)\n    .createdBy("admin")\n    .name("Laptop")\n    .price(999.99)\n    .build();\n```\n\n### @With \u2014 Copias Inmutables\n\n```java\n// En clases inmutables (alternativa a toBuilder para campos individuales):\n@Value   // equivalente a @Data pero todo final (usar record en Java 16+)\n@With    // genera withXxx(value) que retorna copia con ese campo cambiado\npublic class Config {\n    int     timeout;\n    boolean retryEnabled;\n    int     maxRetries;\n}\n\n// Uso:\nConfig base      = new Config(5000, false, 0);\nConfig withRetry = base.withRetryEnabled(true).withMaxRetries(3);\n```\n\n### @NonNull \u2014 Validaci\xf3n de Par\xe1metros\n\n```java\nimport lombok.NonNull;\n\npublic class UserService {\n    // Lombok lanza NullPointerException con mensaje claro si el par\xe1metro es null\n    public UserResponse create(@NonNull CreateUserRequest request) {\n        // no necesita Objects.requireNonNull manual\n        return userMapper.toResponse(userRepository.save(userMapper.toEntity(request)));\n    }\n}\n```\n\n---\n\n## Record \u2014 DTO Inmutable (Java 16+)\n\n```java\n// \u2705 BIEN \u2014 record es conciso, inmutable y genera equals/hashCode/toString\n// En Java 16+, preferir record sobre @Value de Lombok\npublic record CreateUserRequest(\n    @NotBlank  String   name,\n    @Email     String   email,\n    @NotNull   UserRole role\n) {}\n\n// Para respuestas con factory method desde entidad:\npublic record UserResponse(\n    Long     id,\n    String   name,\n    String   email,\n    UserRole role\n) {\n    public static UserResponse from(User user) {\n        return new UserResponse(user.getId(), user.getName(), user.getEmail(), user.getRole());\n    }\n}\n```\n\n> **record vs @Value**: en Java 16+ usar `record`. Usar `@Value` solo para compatibilidad con Java < 16 o cuando se necesita herencia.\n\n---\n\n## Optional \u2014 Null Safety\n\n```java\n// \u274c MAL \u2014 retornar null obliga al caller a chequear\npublic User findById(Long id) {\n    return userRepository.findById(id).orElse(null);\n}\n\n// \u2705 BIEN \u2014 Optional comunica expl\xedcitamente que puede no existir\npublic Optional<User> findById(Long id) {\n    return userRepository.findById(id);\n}\n\n// \u2705 BIEN \u2014 lanzar excepci\xf3n espec\xedfica cuando el elemento es requerido\npublic User getById(Long id) {\n    return userRepository.findById(id)\n        .orElseThrow(() -> new EntityNotFoundException("User", id));\n}\n\n// Encadenado seguro:\nString email = userRepository.findById(id)\n    .map(User::getEmail)\n    .map(String::toLowerCase)\n    .orElse("sin-email@default.com");\n```\n\n---\n\n## Generics \u2014 Sin Duplicaci\xf3n\n\n### Respuesta paginada gen\xe9rica\n\n```java\n// \u2705 Una sola definici\xf3n \u2014 usada en todos los m\xf3dulos\npublic record PaginatedResponse<T>(\n    List<T> content,\n    int     page,\n    int     size,\n    long    totalElements,\n    int     totalPages\n) {\n    public static <T> PaginatedResponse<T> from(Page<T> page) {\n        return new PaginatedResponse<>(\n            page.getContent(),\n            page.getNumber(),\n            page.getSize(),\n            page.getTotalElements(),\n            page.getTotalPages()\n        );\n    }\n}\n```\n\n### Resultado gen\xe9rico (Success / Failure)\n\n```java\n// sealed + record \u2014 discriminated union type-safe (Java 17+)\npublic sealed interface Result<T> permits Result.Success, Result.Failure {\n\n    record Success<T>(T value)                         implements Result<T> {}\n    record Failure<T>(String message, String code)     implements Result<T> {}\n\n    static <T> Result<T> success(T value)                     { return new Success<>(value); }\n    static <T> Result<T> failure(String message, String code) { return new Failure<>(message, code); }\n\n    default boolean isSuccess() { return this instanceof Success<T>; }\n}\n\n// Uso con pattern matching (Java 21+):\nswitch (result) {\n    case Result.Success<User> s -> log.info("Usuario creado: {}", s.value().getId());\n    case Result.Failure<User> f -> log.error("Error {}: {}", f.code(), f.message());\n}\n```\n\n### Repositorio base gen\xe9rico\n\n```java\npublic interface BaseRepository<T, ID> {\n    Optional<T>  findById(ID id);\n    List<T>      findAll();\n    Page<T>      findAll(Pageable pageable);\n    T            save(T entity);\n    void         deleteById(ID id);\n    boolean      existsById(ID id);\n}\n```\n\n---\n\n## Service Pattern (Spring Boot + Lombok completo)\n\n```java\n@Service\n@RequiredArgsConstructor   // constructor injection autom\xe1tico\n@Slf4j                     // logger "log" disponible\n@Transactional(readOnly = true)  // read-only por defecto, override en escrituras\npublic class UserService {\n\n    private final UserRepository userRepository;\n    private final UserMapper     userMapper;\n\n    public UserResponse getById(Long id) {\n        return userRepository.findById(id)\n            .map(userMapper::toResponse)\n            .orElseThrow(() -> new EntityNotFoundException("User", id));\n    }\n\n    @Transactional    // override de readOnly \u2014 escritura\n    public UserResponse create(@NonNull CreateUserRequest request) {\n        if (userRepository.existsByEmail(request.email())) {\n            throw new ConflictException("Email already in use", "EMAIL_CONFLICT");\n        }\n\n        User user  = userMapper.toEntity(request);\n        User saved = userRepository.save(user);\n        log.info("User created id={} email={}", saved.getId(), saved.getEmail());\n        return userMapper.toResponse(saved);\n    }\n\n    @Transactional\n    public UserResponse update(Long id, @NonNull UpdateUserRequest request) {\n        User user = userRepository.findById(id)\n            .orElseThrow(() -> new EntityNotFoundException("User", id));\n\n        userMapper.updateEntity(user, request);\n        log.info("User updated id={}", id);\n        return userMapper.toResponse(userRepository.save(user));\n    }\n}\n```\n\n---\n\n## Streams \u2014 Collections sin Loops Imperativos\n\n```java\n// \u274c MAL \u2014 loop imperativo\nList<String> emails = new ArrayList<>();\nfor (User user : users) {\n    if (user.isActive()) {\n        emails.add(user.getEmail().toLowerCase());\n    }\n}\n\n// \u2705 BIEN \u2014 stream declarativo\nList<String> emails = users.stream()\n    .filter(User::isActive)\n    .map(User::getEmail)\n    .map(String::toLowerCase)\n    .collect(Collectors.toList());\n\n// Agrupar:\nMap<UserRole, List<User>> byRole = users.stream()\n    .collect(Collectors.groupingBy(User::getRole));\n\n// Reducir:\nOptionalDouble avgAge = users.stream()\n    .mapToInt(User::getAge)\n    .average();\n\n// Verificar condici\xf3n:\nboolean allActive = users.stream().allMatch(User::isActive);\nboolean anyAdmin  = users.stream().anyMatch(u -> u.getRole() == UserRole.ADMIN);\n```\n\n---\n\n## Exception Hierarchy \u2014 Sin Capturar Gen\xe9ricos\n\n```java\n// Jerarqu\xeda propia \u2014 evita lanzar/capturar Exception gen\xe9rico\n@Getter\npublic class DomainException extends RuntimeException {\n    private final String code;\n\n    public DomainException(String message, String code) {\n        super(message);\n        this.code = code;\n    }\n}\n\npublic class EntityNotFoundException extends DomainException {\n    public EntityNotFoundException(String entity, Object id) {\n        super(entity + " with id " + id + " not found", entity.toUpperCase() + "_NOT_FOUND");\n    }\n}\n\npublic class ConflictException extends DomainException {\n    public ConflictException(String message, String code) {\n        super(message, code);\n    }\n}\n\n// \u274c MAL\ntry { riskyOperation(); } catch (Exception e) { e.printStackTrace(); }\n\n// \u2705 BIEN\ntry {\n    riskyOperation();\n} catch (SpecificException e) {\n    log.error("Error procesando operaci\xf3n: {}", e.getMessage(), e);\n    throw new DomainException("Error en operaci\xf3n X", "OP_X_ERROR");\n}\n```\n\n---\n\n## Guard Clauses \u2014 Inputs al Inicio\n\n```java\n// \u274c MAL \u2014 l\xf3gica principal enterrada en niveles de if anidados\npublic void processOrder(Order order) {\n    if (order != null) {\n        if (order.getItems() != null && !order.getItems().isEmpty()) {\n            if (order.getTotal() > 0) { /* l\xf3gica */ }\n        }\n    }\n}\n\n// \u2705 BIEN \u2014 fail fast con @NonNull de Lombok + guard clauses\npublic void processOrder(@NonNull Order order) {\n    if (order.getItems() == null || order.getItems().isEmpty()) {\n        throw new IllegalArgumentException("Order must have at least one item");\n    }\n    if (order.getTotal() <= 0) {\n        throw new IllegalArgumentException("Order total must be positive");\n    }\n    // l\xf3gica principal sin anidaci\xf3n\n}\n```\n\n---\n\n## Pattern Matching \u2014 Sin Casteos (Java 16+)\n\n```java\n// \u274c MAL \u2014 casteo expl\xedcito\nif (obj instanceof String) { String s = (String) obj; s.length(); }\n\n// \u2705 BIEN \u2014 pattern matching\nif (obj instanceof String s) { s.length(); }\n\n// \u2705 MEJOR \u2014 switch expression con sealed classes (Java 21+)\nString description = switch (shape) {\n    case Circle    c -> "C\xedrculo de radio " + c.radius();\n    case Rectangle r -> "Rect\xe1ngulo " + r.width() + "x" + r.height();\n    case Triangle  t -> "Tri\xe1ngulo de base " + t.base();\n};\n```\n\n---\n\n## Constantes \u2014 Sin Magic Values\n\n```java\npublic final class UserConstants {\n    private UserConstants() {}\n\n    public static final int      MAX_FAILED_ATTEMPTS = 5;\n    public static final String   CACHE_KEY_PREFIX    = "user_";\n    public static final Duration SESSION_EXPIRY      = Duration.ofHours(8);\n    public static final int      MAX_NAME_LENGTH     = 100;\n}\n```\n\n---\n\n## Commands\n\n```bash\n# Compilar\nmvn compile\n./gradlew compileJava\n\n# Tests\nmvn test\n./gradlew test\n\n# Tests con reporte de cobertura (JaCoCo)\nmvn verify\n./gradlew jacocoTestReport\n\n# An\xe1lisis est\xe1tico (SpotBugs)\nmvn spotbugs:check\n./gradlew spotbugsMain\n\n# Checkstyle (estilo de c\xf3digo)\nmvn checkstyle:check\n./gradlew checkstyleMain\n\n# Formateo autom\xe1tico (Spotless)\nmvn spotless:apply\n./gradlew spotlessApply\n\n# Ver qu\xe9 genera Lombok (delomboked)\nmvn lombok:delombok\n./gradlew delombok\n\n# Ejecutar aplicaci\xf3n Spring Boot\nmvn spring-boot:run\n./gradlew bootRun\n```\n\n---\n\n## Project-Specific Notes\n\nAdapt\xe1 esta secci\xf3n a las convenciones de tu proyecto:\n\n- Versi\xf3n de Java: 17+ (LTS recomendado) o 21+ para virtual threads y pattern matching completo\n- Framework: Spring Boot 3.x / Quarkus / Micronaut / Java puro\n- ORM: Spring Data JPA / Hibernate / jOOQ / JDBC Template\n- **Lombok**: siempre habilitado \u2014 agregar dependencia y plugin en pom.xml / build.gradle\n- Testing: JUnit 5 + Mockito + AssertJ\n- Build tool: Maven o Gradle (adaptar comandos)\n\n### Dependencia Lombok (Maven)\n\n```xml\n<dependency>\n    <groupId>org.projectlombok</groupId>\n    <artifactId>lombok</artifactId>\n    <version>1.18.34</version>\n    <scope>provided</scope>\n</dependency>\n```\n\n### Dependencia Lombok (Gradle)\n\n```groovy\ncompileOnly \'org.projectlombok:lombok:1.18.34\'\nannotationProcessor \'org.projectlombok:lombok:1.18.34\'\n// Para tests:\ntestCompileOnly \'org.projectlombok:lombok:1.18.34\'\ntestAnnotationProcessor \'org.projectlombok:lombok:1.18.34\'\n```\n'})})]})}function u(e={}){const{wrapper:n}={...(0,t.R)(),...e.components};return n?(0,r.jsx)(n,{...e,children:(0,r.jsx)(d,{...e})}):d(e)}},8453:(e,n,a)=>{a.d(n,{R:()=>o,x:()=>s});var r=a(6540);const t={},i=r.createContext(t);function o(e){const n=r.useContext(i);return r.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function s(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(t):e.components||t:o(e.components),r.createElement(i.Provider,{value:n},e.children)}}}]);